import argparse
import json
import os
from pathlib import Path

import numpy as np
import soundfile as sf
import torch
from torch.utils.data import DataLoader, Dataset
from transformers import AutoFeatureExtractor

from model import build_model


def _candidate_roots(base: Path):
    cands = []
    if base.exists():
        cands.append(base)
        if base.is_file():
            cands.append(base.parent)
        try:
            for p in base.rglob('*'):
                if p.is_dir():
                    cands.append(p)
                else:
                    cands.append(p.parent)
        except Exception:
            pass
    extra_envs = [os.environ.get('RAB_DATA_DIR'), '/data', '/rab_data', '/workspace']
    for e in extra_envs:
        if not e:
            continue
        p = Path(e)
        if p.exists():
            cands.append(p)
            try:
                for q in p.rglob('*'):
                    if q.is_dir():
                        cands.append(q)
                    else:
                        cands.append(q.parent)
            except Exception:
                pass
    seen = set()
    uniq = []
    for p in cands:
        try:
            rp = p.resolve()
        except Exception:
            rp = p
        s = str(rp)
        if s not in seen:
            seen.add(s)
            uniq.append(rp)
    return uniq


def resolve_test_root(data_path: str) -> Path:
    base = Path(data_path)
    roots = _candidate_roots(base)

    for cand in roots:
        if (cand / 'test.txt').is_file() and (cand / 'flac').is_dir():
            return cand

    for cand in roots:
        if cand.name == 'flac' and cand.is_dir():
            parent = cand.parent
            if (parent / 'test.txt').is_file():
                return parent

    txt_files = []
    flac_dirs = []
    for cand in roots:
        if cand.name == 'test.txt' and cand.is_file():
            txt_files.append(cand)
        if cand.name == 'flac' and cand.is_dir():
            flac_dirs.append(cand)
        if (cand / 'test.txt').is_file():
            txt_files.append(cand / 'test.txt')
        if (cand / 'flac').is_dir():
            flac_dirs.append(cand / 'flac')

    txt_files = list({str(p): p for p in txt_files}.values())
    flac_dirs = list({str(p): p for p in flac_dirs}.values())

    for txt in txt_files:
        txt_parent = txt.parent
        if (txt_parent / 'flac').is_dir():
            return txt_parent
        for flac in flac_dirs:
            if flac.parent == txt_parent:
                return txt_parent

    raise FileNotFoundError(f'Could not locate test root under {data_path}')


class TestDataset(Dataset):
    def __init__(self, data_path: str):
        self.data_path = resolve_test_root(data_path)
        with open(self.data_path / 'test.txt') as f:
            self.utt_ids = [line.strip() for line in f if line.strip()]
        self.flac_dir = self.data_path / 'flac'
        self.lengths = []
        for utt in self.utt_ids:
            info = sf.info(str(self.flac_dir / f'{utt}.flac'))
            self.lengths.append(int(info.frames))
        self.order = np.argsort(np.asarray(self.lengths))

    def __len__(self):
        return len(self.utt_ids)

    def __getitem__(self, idx):
        real_idx = int(self.order[idx])
        utt = self.utt_ids[real_idx]
        wav, sr = sf.read(self.flac_dir / f'{utt}.flac')
        if wav.ndim > 1:
            wav = wav.mean(axis=1)
        wav = wav.astype(np.float32)
        if sr != 16000:
            raise ValueError(f'Expected 16k audio, got {sr}')
        return {'input_values': wav, 'orig_index': real_idx}


class Collator:
    def __init__(self, feature_extractor):
        self.feat = feature_extractor

    def __call__(self, batch):
        wavs = [b['input_values'] for b in batch]
        enc = self.feat(
            wavs,
            sampling_rate=16000,
            return_tensors='pt',
            padding=True,
            return_attention_mask=True,
        )
        input_values = enc['input_values']
        attention_mask = enc['attention_mask'] if 'attention_mask' in enc else torch.ones_like(input_values, dtype=torch.long)
        return {
            'input_values': input_values,
            'attention_mask': attention_mask,
            'orig_index': [b['orig_index'] for b in batch],
        }


def load_feature_extractor(ckpt):
    local_dir = ckpt.get('feature_extractor_local_dir')
    if local_dir and Path(local_dir).exists():
        feat = AutoFeatureExtractor.from_pretrained(local_dir, local_files_only=True)
    elif Path('artifacts/feature_extractor').exists():
        feat = AutoFeatureExtractor.from_pretrained('artifacts/feature_extractor', local_files_only=True)
    else:
        feat = AutoFeatureExtractor.from_pretrained(ckpt['feature_extractor_name'], local_files_only=True)
    if hasattr(feat, 'return_attention_mask'):
        feat.return_attention_mask = True
    return feat


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, required=True)
    parser.add_argument('--output', type=str, required=True)
    parser.add_argument('--batch_size', type=int, default=64)
    parser.add_argument('--num_workers', type=int, default=8)
    args = parser.parse_args()

    ckpt = torch.load(args.checkpoint, map_location='cpu')
    model = build_model(ckpt['model_config'])
    model.load_state_dict(ckpt['model_state'])
    feature_extractor = load_feature_extractor(ckpt)

    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    amp_dtype = torch.bfloat16 if device.type == 'cuda' and torch.cuda.is_bf16_supported() else torch.float16
    model.to(device)
    model.eval()

    ds = TestDataset(args.data_path)
    loader = DataLoader(
        ds,
        batch_size=args.batch_size,
        shuffle=False,
        num_workers=args.num_workers,
        pin_memory=(device.type == 'cuda'),
        collate_fn=Collator(feature_extractor),
        persistent_workers=args.num_workers > 0,
    )

    preds = np.zeros(len(ds), dtype=np.float32)
    with torch.no_grad():
        for batch in loader:
            x = batch['input_values'].to(device, non_blocking=True)
            m = batch['attention_mask'].to(device, non_blocking=True)
            with torch.amp.autocast('cuda', dtype=amp_dtype, enabled=device.type == 'cuda'):
                logits = model(x, m).float().cpu().numpy()
            for idx, score in zip(batch['orig_index'], logits):
                preds[idx] = float(score)

    with open(args.output, 'w') as f:
        json.dump({'predictions': preds.tolist()}, f)


if __name__ == '__main__':
    main()
